async function loadUserData() {
  console.log('1. Requesting data...');

  // fetch returns a Promise. We await the Response object.
  const response = await fetch('https://jsonplaceholder.typicode.com/users/1');

  console.log('2. Got headers, status:', response.status); // 200

  // We must await AGAIN to parse the body of the response
  const data = await response.json();

  console.log('3. User Name:', data.name);
}

loadUserData();

